<?php
$root=dirname(__DIR__);$iterator=new RecursiveIteratorIterator(new RecursiveDirectoryIterator($root,FilesystemIterator::SKIP_DOTS));$errors=[];$count=0;foreach($iterator as $file){if($file->getExtension()!=='php'||str_contains($file->getPathname(),DIRECTORY_SEPARATOR.'vendor'.DIRECTORY_SEPARATOR))continue;$count++;$cmd=escapeshellarg(PHP_BINARY).' -l '.escapeshellarg($file->getPathname()).' 2>&1';exec($cmd,$out,$code);if($code!==0)$errors[]=implode("\n",$out);$out=[];}if($errors){fwrite(STDERR,implode("\n\n",$errors)."\n");exit(1);}echo "{$count} arquivos PHP válidos.\n";
